import{_ as a,o as t,c as _,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"5-4型重型动力作战服","description":"","frontmatter":{},"headers":[],"relativePath":"7.UA/4.物品与装备/4.载具/5-4型重型动力作战服.md","filePath":"7.UA/4.物品与装备/4.载具/5-4型重型动力作战服.md"}'),o={name:"7.UA/4.物品与装备/4.载具/5-4型重型动力作战服.md"};function d(l,r,b,i,p,c){return t(),_("div",null,[...r[0]||(r[0]=[e("h1",{id:"_5-4型重型动力作战服",tabindex:"-1"},[n("5-4型重型动力作战服 "),e("a",{class:"header-anchor",href:"#_5-4型重型动力作战服","aria-label":'Permalink to "5-4型重型动力作战服"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序002")])])],-1),s('<h1 id="_5-4型重型动力作战服-1" tabindex="-1">5-4型重型动力作战服 <a class="header-anchor" href="#_5-4型重型动力作战服-1" aria-label="Permalink to &quot;5-4型重型动力作战服&quot;">​</a></h1><p>5-4型重型动力作战服    C+1000<br> 简介:劫掠者身披厚重的新型合金钢护甲。指挥官通常会为了支援陆战队对抗重型单位而部署他们。劫掠者的榴弹发射器能发射上百枚可以有效穿甲的惩罚者榴弹，来提供非常稀缺的反装甲打击。这些最早为破坏异虫的硬化甲壳而设计的重型火力可以对建筑和地面装甲单位造成强力杀伤。<br> 载具类型:战斗机器人<br> 体积:7<br> 移动速度/轮：50米<br> 防御面:15<br> 结构值:32<br> 载员:体积不大于6的驾驶员1名<br> 特性:震荡弹，动能泡沫，K12榴弹制造系统，超级强化剂,生命维持系统。<br> 震荡弹: 这种改进可以在惩罚者榴弹的爆炸范围里引发一场暂时的引力混乱,爆炸带来的折跃效应会降低目标范围里大多数地面单位的移动速度。对惩罚者榴弹爆炸范围内的敌方目标移动速度减半，且不可进行冲锋,视为D级困难地形持续1轮。<br> 动能泡沫:沃尔夫工业推出了动能泡沫衬衣，能更好的化解护甲所承受的猛烈冲击，为士兵提供保护。获得2点钝击伤害吸收。<br> K12榴弹制造系统:一个微型弹药制造厂，可以随时补给所需的弹药，大大增强了前线续航能力。视为惩罚者榴弹无限弹药。<br> 超级强化剂:兴奋剂这种东西自联邦建立以来就存在了，无数年来兴奋剂都是前线步兵的标配，但这种化学药剂也会对人体的精神和肉体产生破坏。而经过隐秘特战队的科学家们的改进后己经不会再对人体有精神和肉体上的摧残还会治疗伤囗，但这毕竟是个化学药剂，如果在一天之內使用过多的话仍然会对服用者造成伤害。穿戴者一天只能使用3次，穿戴者以一个移动动作注入药剂，获得1快速医疗（医疗点12）移速增加4米/轮，获得1dp攻击检定加成。持续1场景。<br> 生命维持系统:高效的冷却系统以及自循环气体装置能让穿戴者抵御恶劣环境及宇宙辐射的影响，使作战服的内部环境始终保持适益的温度。视为拥有C级环境免疫。并为驾驶员提供全遮蔽效果，并额外为驾驶员提供遮蔽防御，其数值值为载具体积/被遮蔽者体积取低。<br> 武器系统:惩罚者榴弹发射器发射惩罚者穿甲榴弹 伤害8L  高速5  破甲3 射程200米 能在攻击落地产生半径为3米爆炸，防御对抗</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
